using System.Text.Json;
using System.Text.Json.Serialization.Metadata;

var options = new JsonSerializerOptions
{
    TypeInfoResolver = new DefaultJsonTypeInfoResolver()
};

// 1) Strongly-typed metadata retrieval: GetTypeInfo<T>()
JsonTypeInfo<Person> personInfo = (JsonTypeInfo<Person>)options.GetTypeInfo(typeof(Person));
Console.WriteLine($"Got JsonTypeInfo<Person>: Type = {personInfo.Type.Name}");

// Demonstrate it works — serialize via the typed metadata
var json = JsonSerializer.Serialize(new Person("Alice", 30), personInfo);
Console.WriteLine($"Serialized: {json}");

// 2) Probe without throwing: TryGetTypeInfo
//    With the DefaultJsonTypeInfoResolver every type succeeds, so we also
//    show a case with a limited source-gen context where a type is NOT known.

if (options.TryGetTypeInfo(typeof(Person), out JsonTypeInfo? info))
{
    Console.WriteLine($"\nTryGetTypeInfo(Person) => true, Type = {info!.Type.Name}");
}

// Now use options that have NO resolver — TryGetTypeInfo returns false instead of throwing.
var limited = new JsonSerializerOptions();  // no TypeInfoResolver set
limited.TypeInfoResolver = new EmptyResolver();

if (limited.TryGetTypeInfo(typeof(Person), out JsonTypeInfo? missing))
{
    Console.WriteLine($"TryGetTypeInfo(Person) on limited => true");
}
else
{
    Console.WriteLine($"\nTryGetTypeInfo(Person) on limited => false (metadata not available)");
}

Console.WriteLine("\nDone.");

// --- Types ---

record Person(string Name, int Age);

// A resolver that resolves nothing — simulates a context without a given type.
sealed class EmptyResolver : IJsonTypeInfoResolver
{
    public JsonTypeInfo? GetTypeInfo(Type type, JsonSerializerOptions options) => null;
}

